;  ◆デールコインの森◆

name = デールコインの森
insideName = Lost Forest
level = 4
bgm = garden
isOutdoor = true
shadow = dark
sky = forest
outfield = soil
roof = stone
blank = rock

; 画像パーツ
━ = stone
－ = wood
　 = soil
❖ = soil
⏃ = woods
△ = rock
／ = door
∮ = silver
☗ = gate
︻ = panel
⑴ = bulletin
⑻ = trash
⑼ = trash
⑽ = trash
⑾ = trash
⑿ = trash
⒀ = br_maxhp
⒁ = empty
⒂ = empty

; 敵情報
maxGroups = 2
monsters = ポイズンスライム,フェアリー,ジャイアントバット,巨大ぐも,スケルトン
traps = 毒針,毒ガス,酸スプレー,しびれ針,魔力吸収,爆弾,スモーク

; 移動ポイント
(A) = map:サファイアシティ, enter:サファイアシティ・北西門, ask:Enter town?
(B) = map:ポラリスの神殿, x:3, y:0, way:n, symbol:cave, ask:Go to the dungeon?
(C) = x:15, y:11, stealth:true
(D) = x:8, y:15, stealth:true

; 宝箱
box[1] = トマホーク,ツインロッド,レンジャーブーツ,硬い革鎧,金貨（小）,曲刀兵の書
box[2] = 胸当て,ジャンプの巻物,ジャンプの巻物,金貨（大）
box[3] = 鍵付き宝箱,エレメントプレート・土,エレメントプレート・水,エレメントプレート・火,エレメントプレート・風,精霊の台座のメモ

