[texton]
There's an item hidden inside the barrel![k]
[textoff]
@getitem item=ジャンプの巻物

[eventoff]
;-------------------------------------------------------------------------------
*_set_plate_on_monument
; 台座にエレメントプレートをセットする

@btmes off
[if exp='f[tf.temp] !== void']
	@image layer=4 left=304 top=112 visible=true storage=&'"slot_" + o[f[tf.temp]].img.substr(13)'
	[texton w=5]
	[if exp='game.onUseEventItem']
		@wait time=50
		[nw]It's a spirit pedestal. The slot already has a [emb exp='o[f[tf.temp]].displayName'] in it.[/nw][k]
	[else]
		[nw]It's a spirit pedestal. [emb exp='o[f[tf.temp]].displayName'] is inserted into the slot.[/nw][k]
	[endif]
	[textoff]
	@question title="Do you want to remove it?" cond='! game.warpSpellEnabled'
	[if exp='tf.result']
		@playse storage=switch1
		@image layer=4 left=304 top=112 visible=true storage="slot_empty"
		[texton]
		[nw]Removed [emb exp='f[tf.temp]'] from the slot![/nw][k]
		[textoff]
		@getitem item=&'f[tf.temp]'
		@eval exp='f[tf.temp] = void'
	[endif]
	@layopt layer=4 left=0 top=0 visible=false
	[eventoff]
[endif]

[if exp='! game.onUseEventItem']
	@image layer=4 left=304 top=112 visible=true storage="slot_empty"
	[texton w=5]
	[nw]There is a pedestal. On it is written [b]Spirit Pedestal[/b].[/nw][k]
	[nw]There is a slot on the top that suggests something should be placed in it.[/nw][k]
	[textoff]
	@layopt layer=4 left=0 top=0 visible=false
	[eventoff]
[endif]

@eval exp='f[tf.temp] = game.curItem.name'
@image layer=4 left=304 top=112 visible=true storage="slot_empty"
@wait time=100
@playse storage=switch1
@image layer=4 left=304 top=112 visible=true storage=&'"slot_" + game.curItem.img.substr(13)'
[texton w=5]
[nw]I inserted [emb exp='game.curItem.displayName'] into the slot![/nw][k]
[textoff]
@layopt layer=4 left=0 top=0 visible=false
@eval exp='game.party.ejectItem(game.curItem)'

@jump target=*_failed_to_set cond='f.northSlotOnMonument != "エレメントプレート・風"'
@jump target=*_failed_to_set cond='f.southSlotOnMonument != "エレメントプレート・土"'
@jump target=*_failed_to_set cond='f.eastSlotOnMonument != "エレメントプレート・水"'
@jump target=*_failed_to_set cond='f.westSlotOnMonument != "エレメントプレート・火"'

@wait time=1000
@se f=shakin4
@image layer=e0 mode=psdodge5 opacity=0 storage=screen_white visible=true
@move layer=e0 time=500 path=,,96
@wm
@wait time=2000
@move layer=e0 time=500 path=,,0
@wm
@wait time=500
[texton]
[nw]Suddenly, the pedestal emitted a glow, which then subsided.[/nw][k]
[textoff]
@se f=period
@notice text=&'"<y>The " + o.ワープ.displayName + " spell can now be used!"'
@eval exp='game.warpSpellEnabled = true'

[eventoff]
;------------------------------------------------------------------------------
*_failed_to_set

[eventoff cond='f.northSlotOnMonument === void']
[eventoff cond='f.southSlotOnMonument === void']
[eventoff cond='f.eastSlotOnMonument === void']
[eventoff cond='f.westSlotOnMonument === void']

@wait time=1000
[texton]
[nw]I put the four plates into the pedestal but nothing happened. Is something wrong?[/nw][k]
[textoff]

[eventoff]
;-------------------------------------------------------------------------------
